const site = env.get("MQTT_SITE") || "amq1";
const root = env.get("MQTT_TOPIC_ROOT") || "sensors";
const deviceCount = parseInt(env.get("DEVICE_COUNT") || "25", 10);
const pod = env.get("HOSTNAME") || "nodered";

const factories = (env.get("FACTORIES") || "plant-a,plant-b").split(",").map(s=>s.trim()).filter(Boolean);
const lines = (env.get("LINES") || "line-1,line-2,line-3").split(",").map(s=>s.trim()).filter(Boolean);
const sensorTypes = (env.get("SENSOR_TYPES") || "temp,humidity,vibration,pressure").split(",").map(s=>s.trim()).filter(Boolean);

let seq = context.get("seq") || {};
const idx = Math.floor(Math.random() * deviceCount) + 1;
const deviceId = `device-${idx}`;
seq[deviceId] = (seq[deviceId] || 0) + 1;
context.set("seq", seq);

const factory = factories[idx % factories.length];
const line = lines[idx % lines.length];
const sensorType = sensorTypes[idx % sensorTypes.length];

function rnd(min,max){ return Math.round((min + Math.random()*(max-min))*100)/100; }
let value = 0, unit = "";
if(sensorType === "temp"){ value = rnd(18, 35); unit = "C"; }
else if(sensorType === "humidity"){ value = rnd(25, 85); unit = "%"; }
else if(sensorType === "vibration"){ value = rnd(0.01, 2.5); unit = "g"; }
else if(sensorType === "pressure"){ value = rnd(0.8, 1.4); unit = "bar"; }
else { value = rnd(0, 100); unit = "u"; }

const eventId = `${Date.now().toString(36)}-${pod}-${Math.random().toString(36).slice(2)}`;
const topic = `${root}/${site}/factory/${factory}/line/${line}/device/${deviceId}/${sensorType}/telemetry`;

msg.topic = topic;
msg.payload = {
  schemaVersion: 1,
  site,
  producer: pod,
  eventId,
  deviceId,
  seq: seq[deviceId],
  ts: new Date().toISOString(),
  topic,
  sensor: {
    type: sensorType,
    reading: { value, unit },
    batteryPct: Math.floor(60 + Math.random()*40),
    status: value > 0 ? "OK" : "UNKNOWN"
  },
  location: { factory, line }
};

node.warn("publish " + topic + " eventId=" + eventId + " value=" + value + unit);
return msg;
